sealed class OrderStatus 
    permits Pending, Confirmed, Delivered {}

final class Pending extends OrderStatus {
    String eta;
}

final class Confirmed extends OrderStatus {
    String restaurant;
}

final class Delivered extends OrderStatus {
    String time;
}

